def get_practice_plan(profession: str) -> list[dict[str, str]]:
    name = (profession or "").lower()
    if "frontend" in name:
        return [
            {"id": "frontend-html", "title": "HTML и семантика", "level": "easy", "goal": "разобрать структуру страницы и семантические теги", "prompt": "Сверстай карточку статьи с заголовком, описанием, списком тегов и кнопкой действия. Учитывай семантические теги.", "success": "Есть корректная структура, читаемые теги section/article/header/footer и понятная иерархия.", "hint": "Начни с article, header, p и button."},
            {"id": "frontend-js", "title": "JavaScript логика", "level": "medium", "goal": "отработать функции, массивы и события", "prompt": "Сделай фильтрацию списка карточек по введённой строке поиска.", "success": "Список фильтруется по тексту без перезагрузки страницы, логика вынесена в функцию.", "hint": "Используй input event и Array.filter."},
            {"id": "frontend-react", "title": "React состояние", "level": "hard", "goal": "научиться работать с состоянием и композицией компонентов", "prompt": "Собери интерфейс задач с фильтрами и статусами через React-компоненты.", "success": "Есть отдельные компоненты, состояние поднимается в родителя, UI обновляется без багов.", "hint": "Определи структуру TaskList, FilterBar и TaskCard."},
        ]
    if "backend" in name or "devops" in name:
        return [
            {"id": "backend-api", "title": "REST API", "level": "easy", "goal": "спроектировать простой endpoint и валидацию", "prompt": "Опиши и реализуй endpoint создания задачи с валидацией входных данных.", "success": "Есть маршрут, проверка обязательных полей и корректный ответ сервера.", "hint": "Продумай статусы 200/400 и JSON-ответ."},
            {"id": "backend-db", "title": "Работа с данными", "level": "medium", "goal": "сохранить данные и вернуть нужную структуру", "prompt": "Сделай сохранение сущности и выдачу списка с фильтрацией.", "success": "Данные сохраняются стабильно, выдача предсказуемая, есть фильтрация.", "hint": "Сначала опиши модель данных и контракт API."},
            {"id": "backend-arch", "title": "Архитектура сервиса", "level": "hard", "goal": "разбить логику на слои и подумать о масштабировании", "prompt": "Предложи структуру backend-сервиса для команды и опиши, как вынести бизнес-логику из маршрутов.", "success": "Есть слои controller/service/repository и понятное разделение ответственности.", "hint": "Не смешивай в одном месте HTTP, бизнес-логику и доступ к БД."},
        ]
    return [
        {"id": "general-base", "title": "Базовая задача", "level": "easy", "goal": "проверить понимание ключевой темы профессии", "prompt": f'Опиши, как бы ты подошёл к типовой задаче по направлению "{profession or "Профессия"}".', "success": "Ответ структурирован, показывает понимание цели, шагов и результата.", "hint": "Опиши цель, этапы, риски и критерий успеха."},
        {"id": "general-decision", "title": "Рабочий кейс", "level": "medium", "goal": "разобрать практический сценарий", "prompt": "Разбери рабочий кейс: что нужно сделать сначала, как проверить результат и какие риски учесть.", "success": "Есть порядок действий, критерии проверки и здравый план решения.", "hint": "Начни с диагностики, затем предложи пошаговый план."},
    ]
